options.css:
/* Full-screen panel centering */
html, body {
  height: 100%; /* Full height for the panel */
  margin: 0;
  display: flex;
  justify-content: center; /* Center horizontally */
  align-items: center; /* Center vertically */
  background-color: rgb(144, 149, 143); /* Optional: background color */
}

/* Container to ensure centering */
#flip-counter-container {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100%; /* Ensure the container takes up the full height */
  width: 100%; /* Ensure the container takes up the full width */
}

.flip-counter {
  display: inline-block;
  padding: 5px;
  background-color: rgb(25, 27, 27);
  border-radius: 5px;
  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.4);
}

/* Common style for all flip units */
.flip-unit {
  display: inline-block;
  width: 40px;
  height: 45px;
  margin: 0 5px;
  position: relative;
  flex-wrap: nowrap;
  font-size: 35px;
  font-weight: bold;
  text-align: center;
  line-height: 45px;
  border-radius: 10px;
}

/* Gradient for digits before decimal point */
.black-box {
  background: linear-gradient(145deg, #FADE2A, #FFA500);
  color: rgb(17, 16, 16);
  box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.5); /* Inner shadow for depth */
}

/* Gradient for digit after decimal point */
.white-box {
  background: linear-gradient(145deg, #FADE2A, #FFA500);
  color: black;
  box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2); /* Inner shadow for depth */
}

/* Styling for the decimal point */
.flip-counter span {
  font-size: 35px;
  color: #E5E4E2;
  line-height: 35px;
  padding: 0 4px;
  vertical-align: middle;
}

/* Optional: Animation for flip effect */
@keyframes flip {
  0% {
    transform: rotateX(0deg);
  }
  100% {
    transform: rotateX(-360deg);
  }
}

.flip-unit.flip {
  animation: flip 0.5s;
}

options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
// Get the value from the Grafana query and update the counter display
const htmlgraphicsValue = htmlNode.getElementById('flip-counter');

if (htmlgraphicsValue) {
  const valueField = data.series[0]?.fields[1];
  if (valueField) {
    const length = valueField.values.length;
    let value = valueField.values.get(length - 1);

    // Round the value to one decimal point
    value = value.toFixed(1); // Convert value to a string with 1 decimal place

    // Clear previous digits
    htmlgraphicsValue.innerHTML = '';

    // Loop through the value and handle each digit
    for (let i = 0; i < value.length; i++) {
      const char = value[i];

      // Check if the character is a decimal point, display it without a flip box
      if (char === '.') {
        const decimalPoint = document.createElement('span');
        decimalPoint.textContent = char;
        htmlgraphicsValue.appendChild(decimalPoint);
      } else {
        // Create a flip unit for each digit
        const digit = document.createElement('div');
        digit.classList.add('flip-unit');

        // Apply different colors for digits before and after the decimal point
        if (i < value.indexOf('.')) {
          digit.classList.add('black-box'); // Digits before decimal point
        } else {
          digit.classList.add('white-box'); // Digit after the decimal point
        }

        digit.textContent = char;  // Set the digit value
        htmlgraphicsValue.appendChild(digit);
      }
    }
  } else {
    htmlgraphicsValue.innerHTML = '<div class="flip-unit">No Data</div>';
  }
}

